package com.example.ppm.entity;
import com.baomidou.mybatisplus.annotation.*; import java.time.LocalDateTime;
@TableName("task") public class Task { @TableId(type=IdType.AUTO) private Long id; private String title; @TableField("project_id") private Long projectId; @TableField("owner_id") private Long ownerId; private String type,priority,status,description; @TableField("plan_start_at") private LocalDateTime planStartAt; @TableField("due_at") private LocalDateTime dueAt; @TableField("finished_at") private LocalDateTime finishedAt; @TableField("created_at") private LocalDateTime createdAt; @TableLogic private Integer deleted;
public Long getId(){return id;}public void setId(Long v){id=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public Long getProjectId(){return projectId;}public void setProjectId(Long v){projectId=v;}public Long getOwnerId(){return ownerId;}public void setOwnerId(Long v){ownerId=v;}public String getType(){return type;}public void setType(String v){type=v;}public String getPriority(){return priority;}public void setPriority(String v){priority=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public LocalDateTime getPlanStartAt(){return planStartAt;}public void setPlanStartAt(LocalDateTime v){planStartAt=v;}public LocalDateTime getDueAt(){return dueAt;}public void setDueAt(LocalDateTime v){dueAt=v;}public LocalDateTime getFinishedAt(){return finishedAt;}public void setFinishedAt(LocalDateTime v){finishedAt=v;}public LocalDateTime getCreatedAt(){return createdAt;}}
